from typing_extensions import Annotated

import typer

def test_123(
    name: str,
    boolean_val: bool,  # This will validate that the input is a boolean
    optional_str: Annotated[
        str, typer.Argument()
    ] = "sheeesh",  # This is how to add a default value
):
    import pandas as pd

    print(f"Hello {name}! {boolean_val} {optional_str}")
    df = pd.DataFrame(
        {"name": [name], "boolean_val": [boolean_val], "test": [optional_str]}
    )

    print(df)


if __name__ == "__main__":
    typer.run(test_123)

from typing_extensions import Annotated

import typer

def image_vision_analyzer():
    import os
    from litellm import completion

    llm_key = os.getenv("LLM_KEY")
    llm_base_url = os.getenv("LLM_BASE_URL")

    # openai call
    response = completion(
        model="openai/gpt-4o",
        api_key=llm_key,
        base_url=llm_base_url,
        messages=[
            {
                "role": "user",
                "content": [
                    {"type": "text", "text": "What's in this image?"},
                    {
                        "type": "image_url",
                        "image_url": {
                            "url": "https://upload.wikimedia.org/wikipedia/commons/thumb/d/dd/Gfp-wisconsin-madison-the-nature-boardwalk.jpg/2560px-Gfp-wisconsin-madison-the-nature-boardwalk.jpg"
                        },
                    },
                ],
            }
        ],
    )

    print(response.choices[0].message.content)


if __name__ == "__main__":
    typer.run(image_vision_analyzer)
